public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {

        // ── EvilScheme basic construction ──
        try {
            EvilScheme s = new EvilScheme("Moon Theft", "Gru", 1000000.0);
            check("getSchemeName()", "Moon Theft", s.getSchemeName());
            check("getVillainName()", "Gru", s.getVillainName());
            check("getCost()", "1000000.0", String.valueOf(s.getCost()));
        } catch (Exception e) { fail("EvilScheme constructor/getters", e); }

        // ── displayInfo format ──
        try {
            EvilScheme s = new EvilScheme("Moon Theft", "Gru", 1000000.0);
            check("displayInfo()",
                  "Scheme: Moon Theft by Gru - Cost: $1000000.0",
                  s.displayInfo());
        } catch (Exception e) { fail("displayInfo()", e); }

        // ── addScheme with valid cost ──
        try {
            InvestmentTracker t = new InvestmentTracker();
            t.addScheme("Moon Theft", "Gru", "1000000");
            t.addScheme("Pyramid Scheme", "Vector", "2000000");
            check("addScheme valid: total",
                  "3000000.0",
                  String.valueOf(t.calculateTotalInvestment()));
        } catch (Exception e) { fail("addScheme valid", e); }

        // ── addScheme with invalid cost should not crash ──
        try {
            InvestmentTracker t = new InvestmentTracker();
            t.addScheme("Moon Theft", "Gru", "1000000");
            t.addScheme("Bad Scheme", "Nobody", "lots of money");  // should be caught
            check("addScheme invalid: total unaffected",
                  "1000000.0",
                  String.valueOf(t.calculateTotalInvestment()));
        } catch (Exception e) { fail("addScheme invalid cost", e); }

        // ── calculateTotalInvestment with 3 schemes ──
        try {
            InvestmentTracker t = new InvestmentTracker();
            t.addScheme("A", "V1", "500");
            t.addScheme("B", "V2", "1500");
            t.addScheme("C", "V3", "3000");
            check("calculateTotalInvestment 3 schemes",
                  "5000.0",
                  String.valueOf(t.calculateTotalInvestment()));
        } catch (Exception e) { fail("calculateTotalInvestment", e); }

        // ── findMostExpensiveScheme ──
        try {
            InvestmentTracker t = new InvestmentTracker();
            t.addScheme("Moon Theft", "Gru", "1000000");
            t.addScheme("Pyramid Scheme", "Vector", "2000000");
            t.addScheme("Tiny Heist", "Minion", "50");
            check("findMostExpensiveScheme()",
                  "Pyramid Scheme by Vector ($2000000.0)",
                  t.findMostExpensiveScheme());
        } catch (Exception e) { fail("findMostExpensiveScheme()", e); }

        // ── findMostExpensiveScheme empty ──
        try {
            InvestmentTracker t = new InvestmentTracker();
            check("findMostExpensiveScheme() empty",
                  "No schemes tracked.",
                  t.findMostExpensiveScheme());
        } catch (Exception e) { fail("findMostExpensiveScheme() empty", e); }

        // ── multiple invalid costs ──
        try {
            InvestmentTracker t = new InvestmentTracker();
            t.addScheme("Plan A", "Gru", "999");
            t.addScheme("Plan B", "Vector", "oops");
            t.addScheme("Plan C", "Gru", "1");
            check("multiple invalid: only valid summed",
                  "1000.0",
                  String.valueOf(t.calculateTotalInvestment()));
        } catch (Exception e) { fail("multiple invalid costs", e); }

        // ── summary ──
        System.out.println();
        int total = passed + failed;
        System.out.println((passed == total ? "PASS" : "FAIL")
            + ": " + passed + "/" + total + " tests passed");
    }

    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void fail(String label, Exception e) {
        System.out.println("FAIL: " + label + " \u2014 " + e); failed++;
    }
}
